// VM uptime (% of time Connected heartbeat received) — run in customer LA workspace
Heartbeat
| where TimeGenerated > ago(30d)
| summarize UptimeMinutes=count() by Computer
| extend UptimePct = round(UptimeMinutes / (30.0 * 24.0 * 60.0) * 100, 2)
| order by UptimePct asc

