// Azure Monitor availability test results (for web endpoints)
AppAvailabilityResults
| where TimeGenerated > ago(30d)
| summarize SuccessCount=countif(Success==true),
            TotalCount=count() by TestName, AppRoleName
| extend AvailabilityPct = round(100.0 * SuccessCount / TotalCount, 3)
| order by AvailabilityPct asc

// Disk free space warning: < 15% on any VM
Perf
| where ObjectName == "LogicalDisk"
| where CounterName == "% Free Space"
| where InstanceName !in ("_Total","HarddiskVolume1")
| where CounterValue < 15
| summarize MinFree=min(CounterValue) by Computer, InstanceName
| order by MinFree asc

# Programmatically create a per-customer Azure Monitor Workbook
# (Template-based: swap the subscription parameter per customer)

WORKBOOK_TEMPLATE=$(cat << 'WBEOF'
{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {"json": "## {CustomerName} — Monthly Operations Summary"},
      "name": "header"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "Heartbeat | summarize lastSeen=max(TimeGenerated) by Computer | extend Status = iff(lastSeen > ago(10m), '✅ Connected', '❌ Disconnected') | project Computer, lastSeen, Status",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": ["{CustomerLAWorkspace}"]
      },
      "name": "vm_health"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "AzureActivity | where TimeGenerated > startofmonth(now()) | where HomeTenantId != TenantId | summarize count() by OperationNameValue, ActivityStatusValue | order by count_ desc",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "crossComponentResources": ["{CustomerLAWorkspace}"]
      },
      "name": "msp_actions"
    }
  ]
}
WBEOF
)

# Create workbook for customer A in MSP subscription (references customer LA workspace)
az rest --method PUT   --url "https://management.azure.com/subscriptions/$MSP_SUB_ID/resourceGroups/msp-workbooks-rg/providers/Microsoft.Insights/workbooks/$WORKBOOK_GUID?api-version=2022-04-01"   --body "{
    "kind": "shared",
    "location": "eastus",
    "properties": {
      "displayName": "Customer A — Operations Summary",
      "category": "workbook",
      "serializedData": $(echo "$WORKBOOK_TEMPLATE" | python3 -c 'import json,sys; d=json.load(sys.stdin); print(json.dumps(json.dumps(d)))'),
      "sourceId": "/subscriptions/$MSP_SUB_ID/resourceGroups/msp-workbooks-rg"
    }
  }"

# Get the workbook's shareable URL (for sending to customer)
az rest --method GET   --url "https://management.azure.com/subscriptions/$MSP_SUB_ID/resourceGroups/msp-workbooks-rg/providers/Microsoft.Insights/workbooks/$WORKBOOK_GUID?api-version=2022-04-01"   --query "properties.workbookId"
